#!/usr/bin/env bash
set -euo pipefail

# ── 1. Install Docker ──────────────────────────────────────────────────────────
echo "[1/4] Installing Docker..."
sudo curl -fsSL https://get.docker.com | sh

# ── 2. Create working directory ────────────────────────────────────────────────
echo "[2/4] Creating /opt/remnanode..."
sudo mkdir -p /opt/remnanode
cd /opt/remnanode

# ── 3. Write docker-compose.yml ───────────────────────────────────────────────
echo "[3/4] Writing docker-compose.yml..."
sudo tee docker-compose.yml > /dev/null <<'EOF'
services:
  remnanode:
    container_name: remnanode
    hostname: remnanode
    image: remnawave/node:latest
    network_mode: host
    restart: always
    cap_add:
      - NET_ADMIN
    ulimits:
      nofile:
        soft: 1048576
        hard: 1048576
    environment:
      - NODE_PORT=2222
      - SECRET_KEY=""
EOF

# ── 4. Start the container and follow logs ─────────────────────────────────────
echo "[4/4] Starting remnanode..."
sudo docker compose up -d
sudo docker compose logs -f -t
